INSERT INTO contract_templates (contract_type, jurisdiction, version, title, preamble, recitals, clauses, signature_block, placeholders, is_active, metadata) VALUES (
  'nda_one_way',
  'uk',
  1,
  'One-Way Non-Disclosure Agreement (United Kingdom)',
  'This Non-Disclosure Agreement (the "Agreement") is entered into as of {{effective_date}} (the "Effective Date") by and between (i) {{party_a_company}}, a company registered in England and Wales (or as applicable) with registered address at {{party_a_address}} (the "Disclosing Party" or "{{party_a_name}}"), and (ii) {{party_b_company}}, with address at {{party_b_address}} (the "Receiving Party" or "{{party_b_name}}").',
  'WHEREAS, the Disclosing Party possesses certain confidential and proprietary information that it wishes to disclose to the Receiving Party in connection with {{purpose}} (the "Purpose");

WHEREAS, the Receiving Party wishes to receive such information and agrees to protect its confidentiality in accordance with the terms of this Agreement and applicable UK law, including the UK General Data Protection Regulation (UK GDPR) and the Data Protection Act 2018, where applicable;

NOW, THEREFORE, in consideration of the mutual promises and covenants contained herein and for other good and valuable consideration, the receipt and sufficiency of which are hereby acknowledged, the parties agree as follows:',
  '[{"id":"definitions","title":"1. DEFINITIONS","content":"1.1 \"Confidential Information\" means any non-public information disclosed by or on behalf of the Disclosing Party to the Receiving Party, whether disclosed before or after the Effective Date, and whether disclosed in writing, orally, visually, electronically, or in any other form, that (a) is designated as confidential or proprietary, or (b) reasonably should be understood to be confidential given the nature of the information or the circumstances of disclosure.\n\n1.2 Confidential Information includes, without limitation: business, financial, and product plans; customer and supplier information; pricing; forecasts; marketing information; technical data; inventions; algorithms; designs; specifications; software (including source code and object code); research and development; know-how; processes; analyses; compilations; notes; summaries; and any information derived from Confidential Information.\n\n1.3 \"Trade Secret\" means information which meets the definition of a trade secret under applicable law, including the Trade Secrets (Enforcement, etc.) Regulations 2018. Trade Secrets are included within Confidential Information.\n\n1.4 \"Representatives\" means the Receiving Party''s and its affiliates'' directors, officers, employees, agents, professional advisors (including solicitors and accountants), contractors, and permitted consultants, in each case who have a need to know the Confidential Information for the Purpose and who are bound by confidentiality obligations at least as protective as those in this Agreement.\n\n1.5 \"Personal Data\" shall have the meaning set forth under the UK General Data Protection Regulation (UK GDPR) and the Data Protection Act 2018, to the extent applicable.","type":"standard","order":1},{"id":"confidentiality_obligations","title":"2. CONFIDENTIALITY OBLIGATIONS","content":"2.1 Use Restriction. The Receiving Party shall use the Confidential Information solely for the Purpose and for no other purpose without the Disclosing Party''s prior written consent.\n\n2.2 Non-Disclosure. The Receiving Party shall not disclose the Confidential Information to any person or entity except to its Representatives who have a need to know for the Purpose and are bound by confidentiality obligations at least as protective as this Agreement.\n\n2.3 Standard of Care. The Receiving Party shall protect the Confidential Information using at least the same degree of care the Receiving Party uses to protect its own confidential information of like importance, but in no event less than reasonable care.\n\n2.4 Security Measures. The Receiving Party shall implement and maintain reasonable administrative, technical, and physical safeguards designed to protect the confidentiality and security of the Confidential Information and to prevent unauthorised access, use, or disclosure.\n\n2.5 Compelled Disclosure. If the Receiving Party is required by law, regulation, or valid legal process to disclose any Confidential Information, the Receiving Party shall (to the extent legally permitted) provide the Disclosing Party with prompt written notice and reasonably cooperate (at the Disclosing Party''s expense) in seeking a protective order. If disclosure is ultimately required, the Receiving Party shall disclose only that portion legally required.\n\n2.6 Trade Secret Protections. Nothing in this Agreement limits any rights or remedies available under the Trade Secrets (Enforcement, etc.) Regulations 2018 or other applicable law.\n\n2.7 UK GDPR / Personal Data. To the extent Confidential Information includes Personal Data, the Receiving Party shall (a) comply with applicable UK GDPR and Data Protection Act 2018 requirements; (b) use such Personal Data solely for the Purpose; and (c) maintain appropriate technical and organisational measures to protect the Personal Data.","type":"standard","order":2},{"id":"exclusions","title":"3. EXCLUSIONS FROM CONFIDENTIAL INFORMATION","content":"3.1 Exclusions. Confidential Information does not include information that the Receiving Party can demonstrate by competent written records:\n\n(a) is or becomes publicly available through no breach of this Agreement by the Receiving Party;\n\n(b) was lawfully known to the Receiving Party without restriction prior to disclosure by the Disclosing Party;\n\n(c) is lawfully received from a third party without breach of any obligation of confidentiality;\n\n(d) is independently developed by the Receiving Party without use of or reference to the Confidential Information; or\n\n(e) is approved for release by the Disclosing Party in writing.","type":"standard","order":3},{"id":"term_and_duration","title":"4. TERM AND DURATION","content":"4.1 Term. This Agreement begins on the Effective Date and continues until the earlier of (a) {{expiration_date}}, or (b) termination by either party upon written notice provided at least {{notice_period}} days in advance.\n\n4.2 Survival. The Receiving Party''s obligations shall survive termination for {{confidentiality_period}} years from the date of disclosure of the applicable Confidential Information.\n\n4.3 Trade Secrets. With respect to Trade Secrets, obligations continue for so long as such information remains a Trade Secret under applicable law.","type":"standard","order":4},{"id":"return_of_information","title":"5. RETURN OR DESTRUCTION OF INFORMATION","content":"5.1 Return/Destruction. Upon the Disclosing Party''s written request, the Receiving Party shall promptly return or destroy all Confidential Information, including copies, and certify such return or destruction in writing if requested.\n\n5.2 Archival Copies. The Receiving Party may retain copies required by law or bona fide document retention policies, provided such retained information remains subject to this Agreement.","type":"standard","order":5},{"id":"remedies","title":"6. REMEDIES","content":"6.1 Injunctive Relief. The Receiving Party acknowledges that unauthorised disclosure may cause irreparable harm. The Disclosing Party shall be entitled to seek equitable relief, including injunctive relief, in addition to any other remedies.\n\n6.2 No Limitation of Statutory Rights. This Agreement does not limit rights available under the Trade Secrets (Enforcement, etc.) Regulations 2018 or other applicable law.","type":"negotiable","order":6},{"id":"governing_law","title":"7. GOVERNING LAW; JURISDICTION","content":"7.1 Governing Law. This Agreement shall be governed by and construed in accordance with the law of England and Wales.\n\n7.2 Jurisdiction. The courts of England and Wales shall have exclusive jurisdiction to settle any dispute arising out of this Agreement, except that a party may seek injunctive relief in any court of competent jurisdiction.","type":"standard","order":7},{"id":"general_provisions","title":"8. GENERAL PROVISIONS","content":"8.1 Notices. All notices must be in writing and delivered personally, by courier, Royal Mail signed-for delivery, or email with confirmation.\n\n8.2 No Licence. No licence or rights are granted under any patents, copyrights, trade secrets, or trade marks by disclosure of Confidential Information.\n\n8.3 No Partnership/Agency. Nothing creates any partnership, joint venture, or agency relationship.\n\n8.4 Protected Disclosures. Nothing restricts protected disclosures under the Employment Rights Act 1996 (whistleblowing).\n\n8.5 Severability. Invalid provisions shall be modified to the minimum extent necessary.\n\n8.6 Waiver. Waivers must be in writing.\n\n8.7 Assignment. Neither party may assign without prior written consent, except to a successor in a merger or acquisition.\n\n8.8 Entire Agreement. This Agreement constitutes the entire agreement and supersedes prior understandings. Amendments require written agreement.\n\n8.9 Counterparts. May be executed in counterparts, including electronically.\n\n8.10 Third Party Rights. No third party rights under the Contracts (Rights of Third Parties) Act 1999.","type":"standard","order":8}]'::jsonb,
  'IN WITNESS WHEREOF, the parties have executed this Agreement as of {{signature_date}}.

DISCLOSING PARTY:
{{party_a_company}}

