Email: {{party_a_email}}
Address: {{party_a_address}}
Date: {{signature_date}}

RECEIVING PARTY:
{{party_b_company}}

By (Signature): ________________________________
Printed Name: {{party_b_name}}
Title: {{party_b_title}}
Email: {{party_b_email}}
Address: {{party_b_address}}
Date: {{signature_date}}',
  '[{"id":"party_a_email","token":"{{party_a_email}}","label":"Your Email","description":"Email address of the disclosing party","category":"party_a","type":"email","required":true,"autofillKey":"email"},{"id":"party_a_name","token":"{{party_a_name}}","label":"Your Name","description":"Full legal name of the disclosing party","category":"party_a","type":"text","required":true,"autofillKey":"name"},{"id":"party_a_address","token":"{{party_a_address}}","label":"Your Address","description":"Business or mailing address","category":"party_a","type":"textarea","required":false,"autofillKey":"address"},{"id":"party_a_company","token":"{{party_a_company}}","label":"Your Company","description":"Company or organisation name","category":"party_a","type":"text","required":false,"autofillKey":"company_name"},{"id":"party_a_title","token":"{{party_a_title}}","label":"Your Title","description":"Job title or role","category":"party_a","type":"text","required":false,"autofillKey":"job_title"},{"id":"party_b_email","token":"{{party_b_email}}","label":"Receiving Party Email","description":"Email address of the receiving party","category":"party_b","type":"email","required":true},{"id":"party_b_name","token":"{{party_b_name}}","label":"Receiving Party Name","description":"Full legal name of the receiving party","category":"party_b","type":"text","required":true},{"id":"party_b_address","token":"{{party_b_address}}","label":"Receiving Party Address","description":"Business or mailing address","category":"party_b","type":"textarea","required":false},{"id":"party_b_company","token":"{{party_b_company}}","label":"Receiving Party Company","description":"Company or organisation name","category":"party_b","type":"text","required":false},{"id":"party_b_title","token":"{{party_b_title}}","label":"Receiving Party Title","description":"Job title or role","category":"party_b","type":"text","required":false},{"id":"effective_date","token":"{{effective_date}}","label":"Effective Date","description":"When the agreement becomes effective","category":"dates","type":"date","required":true},{"id":"expiration_date","token":"{{expiration_date}}","label":"Expiration Date","description":"When the agreement ends","category":"dates","type":"date","required":false},{"id":"signature_date","token":"{{signature_date}}","label":"Signature Date","description":"Date of signing","category":"dates","type":"date","required":false},{"id":"confidentiality_period","token":"{{confidentiality_period}}","label":"Confidentiality Period","description":"Duration of confidentiality obligations (years)","category":"terms","type":"number","required":false},{"id":"notice_period","token":"{{notice_period}}","label":"Notice Period","description":"Days notice required for termination","category":"terms","type":"number","required":false},{"id":"purpose","token":"{{purpose}}","label":"Purpose","description":"Purpose of the disclosure","category":"terms","type":"textarea","required":false}]'::jsonb,
  true,
